29	pub fn stringify(global: *JSGlobalObject, callFrame: *jsc.CallFrame) JSError!JSValue {
30	    const value, const replacer, const space_value = callFrame.argumentsAsArray(3);
31	
32	    value.ensureStillAlive();
33	
34	    if (value.isUndefined() or value.isSymbol() or value.isFunction()) {
35	        return .js_undefined;
36	    }
37	
38	    if (!replacer.isUndefinedOrNull()) {
39	        return global.throw("YAML.stringify does not support the replacer argument", .{});
40	    }
41	
42	    var scope: bun.AllocationScope = .init(bun.default_allocator);
43	    defer scope.deinit();
44	
45	    var stringifier: Stringifier = try .init(scope.allocator(), global, space_value);
46	    defer stringifier.deinit();
47	
48	    stringifier.findAnchorsAndAliases(global, value, .root) catch |err| return switch (err) {
49	        error.OutOfMemory, error.JSError, error.JSTerminated => |js_err| js_err,
50	        error.StackOverflow => global.throwStackOverflow(),
51	    };
52	
53	    stringifier.stringify(global, value) catch |err| return switch (err) {
54	        error.OutOfMemory, error.JSError, error.JSTerminated => |js_err| js_err,
55	        error.StackOverflow => global.throwStackOverflow(),
56	    };
57	
58	    return stringifier.builder.toString(global);
59	}
