809	        var base: enum { dec, hex, oct } = .dec;
810	
811	        next: switch (str.charAt(i)) {
812	            '.' => {
813	                if (dot or base != .dec) {
814	                    offset.* = i;
815	                    return false;
816	                }
817	                dot = true;
818	                i += 1;
819	                if (i < str.length()) {
820	                    continue :next str.charAt(i);
821	                }
822	                return true;
823	            },
824	
825	            '+' => {
826	                if (@"+") {
827	                    offset.* = i;
828	                    return false;
829	                }
830	                @"+" = true;
831	                i += 1;
832	                if (i < str.length()) {
833	                    continue :next str.charAt(i);
834	                }
835	                return true;
836	            },
837	
838	            '-' => {
839	                if (@"-") {
