841	                    return false;
842	                }
843	                @"-" = true;
844	                i += 1;
845	                if (i < str.length()) {
846	                    continue :next str.charAt(i);
847	                }
848	                return true;
849	            },
850	
851	            '0' => {
852	                if (i == start) {
853	                    if (i + 1 < str.length()) {
854	                        switch (str.charAt(i + 1)) {
855	                            'x', 'X' => {
856	                                base = .hex;
857	                            },
858	                            'o', 'O' => {
859	                                base = .oct;
860	                            },
861	                            '0'...'9' => {
862	                                // 0 prefix allowed
863	                            },
864	                            else => {
865	                                offset.* = i;
866	                                return false;
867	                            },
868	                        }
869	                        i += 1;
870	                    } else {
871	                        return true;
872	                    }
873	                }
874	
875	                i += 1;
