442	    const arguments = callframe.arguments_old(4).slice();
443	    if (arguments.len == 0)
444	        return bun.String.empty.toJS(globalThis);
445	
446	    for (arguments) |arg| {
447	        arg.protect();
448	    }
449	    defer {
450	        for (arguments) |arg| {
451	            arg.unprotect();
452	        }
453	    }
454	
455	    var formatOptions = ConsoleObject.FormatOptions{
456	        .enable_colors = false,
457	        .add_newline = false,
458	        .flush = false,
459	        .max_depth = 8,
460	        .quote_strings = true,
461	        .ordered_properties = false,
462	    };
463	    if (arguments.len > 1) {
464	        try formatOptions.fromJS(globalThis, arguments[1..]);
465	    }
466	
467	    // very stable memory address
468	    var array = std.Io.Writer.Allocating.init(bun.default_allocator);
469	    defer array.deinit();
470	    const writer = &array.writer;
471	    // we buffer this because it'll almost always be < 4096
472	    // when it's under 4096, we want to avoid the dynamic allocation
473	    try ConsoleObject.format2(
474	        .Debug,
475	        globalThis,
476	        arguments.ptr,
477	        1,
478	        writer,
479	        formatOptions,
