483	
484	    // we are going to always clone to keep things simple for now
485	    // the common case here will be stack-allocated, so it should be fine
486	    var out = ZigString.init(array.written()).withEncoding();
487	    const ret = out.toJS(globalThis);
488	
489	    return ret;
490	}
