248	JSC_DEFINE_HOST_FUNCTION(functionConcatTypedArrays, (JSGlobalObject * globalObject, JSC::CallFrame* callFrame))
249	{
250	    auto& vm = JSC::getVM(globalObject);
251	    auto throwScope = DECLARE_THROW_SCOPE(vm);
252	
253	    if (callFrame->argumentCount() < 1) [[unlikely]] {
254	        throwTypeError(globalObject, throwScope, "Expected at least one argument"_s);
255	        return {};
256	    }
257	
258	    auto arrayValue = callFrame->uncheckedArgument(0);
259	
260	    size_t maxLength = std::numeric_limits<size_t>::max();
261	    auto arg1 = callFrame->argument(1);
262	    if (!arg1.isUndefined() && arg1.isNumber()) {
263	        double number = arg1.toNumber(globalObject);
264	        if (std::isnan(number) || number < 0) {
265	            throwRangeError(globalObject, throwScope, "Maximum length must be >= 0"_s);
266	            return {};
267	        }
268	        if (!std::isinf(number)) {
269	            maxLength = arg1.toUInt32(globalObject);
270	        }
271	    }
272	
273	    bool asUint8Array = false;
274	    auto arg2 = callFrame->argument(2);
275	    if (!arg2.isUndefined()) {
276	        asUint8Array = arg2.toBoolean(globalObject);
277	    }
278	
279	    RELEASE_AND_RETURN(throwScope, flattenArrayOfBuffersIntoArrayBufferOrUint8Array(globalObject, arrayValue, maxLength, asUint8Array));
280	}
