pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

/// Parse an INI-format string into a JavaScript object.
/// Sections like [foo] become nested objects. Key = value pairs become
/// string, number, boolean, or null properties. Comments (;, #) are ignored.
pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const arguments = callframe.arguments_old(1).slice();
    if (arguments.len == 0 or arguments[0].isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    const js_str = arguments[0];
    const bun_str = try js_str.toBunString(globalThis);
    defer bun_str.deref();
    const utf8 = bun_str.toUTF8(bun.default_allocator);
    defer utf8.deinit();

    var parser = bun.ini.Parser.init(
        bun.default_allocator,
        "<ini>",
        utf8.slice(),
        globalThis.bunVM().transpiler.env,
    );
    defer parser.deinit();

    try parser.parse(parser.arena.allocator());

    return parser.out.toJS(bun.default_allocator, globalThis) catch |e| {
        return globalThis.throwError(e, "failed to parse INI");
    };
}

/// Serialize a JavaScript object into an INI-format string.
/// Root-level scalars are emitted as `key = value`. Root-level objects
/// become `[section]` headers with their own key = value pairs beneath.
/// Nested objects produce dotted section headers: `[section.nested]`.
/// Array values are emitted as repeated `key[] = value` lines.
pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const arguments = callframe.arguments_old(1).slice();
    if (arguments.len == 0 or arguments[0].isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    const value = arguments[0];
    if (!value.isObject()) {
        return globalThis.throwInvalidArguments("INI.stringify: input must be an object", .{});
    }

    // Arena for temporary section-name strings during recursive descent.
    var arena = bun.ArenaAllocator.init(bun.default_allocator);
    defer arena.deinit();

    var s: Stringifier = .{
        .stack_check = .init(),
        .builder = .init(),
    };
    defer s.builder.deinit();

    s.writeSection(globalThis, value, arena.allocator(), "") catch |err| return switch (err) {
        error.OutOfMemory, error.JSError, error.JSTerminated => |js_err| js_err,
        error.StackOverflow => globalThis.throwStackOverflow(),
    };

    return s.builder.toString(globalThis);
}

const Stringifier = struct {
    stack_check: bun.StackCheck,
    builder: wtf.StringBuilder,

    const WriteError = bun.JSError || bun.StackOverflow;

    /// Write the scalars/arrays of `obj` first, then recursively write any
    /// plain-object properties as INI sections.
    ///
    /// `section_prefix` is the dotted path leading to `obj`, e.g. `"foo.bar"`.
    /// It is empty for the root object.
    pub fn writeSection(
        this: *Stringifier,
        global: *JSGlobalObject,
        obj: JSValue,
        arena: std.mem.Allocator,
        section_prefix: []const u8,
    ) WriteError!void {
        if (!this.stack_check.isSafeToRecurse()) return error.StackOverflow;

        const obj_ref = try obj.toObject(global);

        // Pass 1 — emit scalar and array properties.
        {
            var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) =
                try .init(global, obj_ref);
            defer iter.deinit();

            while (try iter.next()) |prop_name| {
                const val = iter.value;
                if (val.isUndefined() or val.isSymbol() or val.isFunction()) continue;
                // Plain objects are deferred to pass 2.
                if (val.isObject() and !val.isArray()) continue;

                const key_utf8 = prop_name.toUTF8(arena);
                const key = key_utf8.slice();

                if (val.isArray()) {
                    var arr_iter = try val.arrayIterator(global);
                    while (try arr_iter.next()) |item| {
                        if (item.isUndefined() or item.isSymbol() or item.isFunction()) continue;
                        // Skip nested objects/arrays inside an array.
                        if (item.isObject()) continue;
                        this.builder.append(.latin1, key);
                        this.builder.append(.latin1, "[] = ");
                        try this.appendScalar(global, item);
                        this.builder.append(.lchar, '\n');
                    }
                } else {
                    this.builder.append(.latin1, key);
                    this.builder.append(.latin1, " = ");
                    try this.appendScalar(global, val);
                    this.builder.append(.lchar, '\n');
                }
            }
        }

        // Pass 2 — emit plain-object properties as [section] headers.
        {
            var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) =
                try .init(global, obj_ref);
            defer iter.deinit();

            while (try iter.next()) |prop_name| {
                const val = iter.value;
                if (!val.isObject() or val.isArray()) continue;

                const key_utf8 = prop_name.toUTF8(arena);
                const key = key_utf8.slice();

                const section_name: []const u8 = if (section_prefix.len > 0)
                    try std.fmt.allocPrint(arena, "{s}.{s}", .{ section_prefix, key })
                else
                    key;

                this.builder.append(.lchar, '\n');
                this.builder.append(.lchar, '[');
                this.builder.append(.latin1, section_name);
                this.builder.append(.lchar, ']');
                this.builder.append(.lchar, '\n');

                try this.writeSection(global, val, arena, section_name);
            }
        }
    }

    fn appendScalar(this: *Stringifier, global: *JSGlobalObject, value: JSValue) bun.JSError!void {
        if (value.isNull()) {
            this.builder.append(.latin1, "null");
        } else if (value.isBoolean()) {
            this.builder.append(.latin1, if (value.asBoolean()) "true" else "false");
        } else if (value.isInt32()) {
            this.builder.append(.int, value.asInt32());
        } else if (value.isNumber()) {
            this.builder.append(.double, value.asNumber());
        } else if (value.isString()) {
            const str = try value.toBunString(global);
            defer str.deref();
            this.builder.append(.string, str);
        }
        // undefined, symbol, function: callers filter these out already.
    }
};

