const { iniInternals } = require("bun:internal-for-testing");
const { parse } = iniInternals;
import { describe, expect, it, test } from "bun:test";
import { bunEnv, bunExe, tempDirWithFiles } from "harness";

describe("Bun.INI", () => {
  describe("parse", () => {
    test("basic key-value", () => {
      expect(Bun.INI.parse("name = my-app\nversion = 1.0.0")).toEqual({
        name: "my-app",
        version: "1.0.0",
      });
    });

    test("sections become nested objects", () => {
      const ini = `
name = root-value

[database]
host = localhost
port = 5432
`;
      expect(Bun.INI.parse(ini)).toEqual({
        name: "root-value",
        database: {
          host: "localhost",
          port: 5432,
        },
      });
    });

    test("dotted section names create deep nesting", () => {
      const ini = `
[foo.bar.baz]
key = value
`;
      expect(Bun.INI.parse(ini)).toEqual({
        foo: { bar: { baz: { key: "value" } } },
      });
    });

    test("boolean values", () => {
      expect(Bun.INI.parse("enabled = true\ndisabled = false")).toEqual({
        enabled: true,
        disabled: false,
      });
    });

    test("null value", () => {
      expect(Bun.INI.parse("x = null")).toEqual({ x: null });
    });

    test("numeric values", () => {
      expect(Bun.INI.parse("port = 5432\npi = 3.14")).toEqual({
        port: 5432,
        pi: "3.14",
      });
    });

    test("comment lines with ; are ignored", () => {
      const ini = `
; this is a comment
key = value
; another comment
`;
      expect(Bun.INI.parse(ini)).toEqual({ key: "value" });
    });

    test("comment lines with # are ignored", () => {
      const ini = `
# this is a comment
key = value
`;
      expect(Bun.INI.parse(ini)).toEqual({ key: "value" });
    });

    test("array values with [] notation", () => {
      const ini = `
colors[] = red
colors[] = green
colors[] = blue
`;
      expect(Bun.INI.parse(ini)).toEqual({
        colors: ["red", "green", "blue"],
      });
    });

    test("empty string input returns empty object", () => {
      expect(Bun.INI.parse("")).toEqual({});
    });

    test("throws on non-string input", () => {
      expect(() => Bun.INI.parse(null as any)).toThrow();
    });
  });

  describe("stringify", () => {
    test("basic key-value", () => {
      expect(Bun.INI.stringify({ name: "my-app", version: "1.0.0" })).toContain("name = my-app");
    });

    test("boolean values", () => {
      const out = Bun.INI.stringify({ enabled: true, disabled: false });
      expect(out).toContain("enabled = true");
      expect(out).toContain("disabled = false");
    });

    test("null value", () => {
      expect(Bun.INI.stringify({ x: null })).toContain("x = null");
    });

    test("numeric value", () => {
      expect(Bun.INI.stringify({ port: 5432 })).toContain("port = 5432");
    });

    test("sections for nested objects", () => {
      const out = Bun.INI.stringify({
        database: { host: "localhost", port: 5432 },
      });
      expect(out).toContain("[database]");
      expect(out).toContain("host = localhost");
      expect(out).toContain("port = 5432");
    });

    test("dotted section names for deep nesting", () => {
      const out = Bun.INI.stringify({
        foo: { bar: { key: "value" } },
      });
      expect(out).toContain("[foo.bar]");
      expect(out).toContain("key = value");
    });

    test("array values use [] notation", () => {
      const out = Bun.INI.stringify({ colors: ["red", "green", "blue"] });
      expect(out).toContain("colors[] = red");
      expect(out).toContain("colors[] = green");
      expect(out).toContain("colors[] = blue");
    });

    test("root scalars appear before sections", () => {
      const out = Bun.INI.stringify({
        name: "app",
        db: { host: "localhost" },
      });
      const nameIdx = out.indexOf("name = app");
      const sectionIdx = out.indexOf("[db]");
      expect(nameIdx).toBeGreaterThanOrEqual(0);
      expect(sectionIdx).toBeGreaterThanOrEqual(0);
      expect(nameIdx).toBeLessThan(sectionIdx);
    });

    test("round-trips basic INI through parse -> stringify -> parse", () => {
      const original = {
        name: "my-app",
        enabled: true,
        count: 42,
        database: { host: "localhost", port: 5432 },
      };
      const ini = Bun.INI.stringify(original);
      const parsed = Bun.INI.parse(ini);
      expect(parsed).toEqual(original);
    });

    test("empty object produces empty string", () => {
      expect(Bun.INI.stringify({})).toBe("");
    });

    test("throws on non-object input", () => {
      expect(() => Bun.INI.stringify("not an object" as any)).toThrow();
    });
  });
});

