const { iniInternals } = require("bun:internal-for-testing");
const { parse } = iniInternals;
import { describe, expect, it, test } from "bun:test";
import { bunEnv, bunExe, tempDirWithFiles } from "harness";

describe("Bun.INI", () => {
  describe("parse", () => {
    test("basic key-value", () => {
      expect(Bun.INI.parse("name = my-app\nversion = 1.0.0")).toEqual({
        name: "my-app",
        version: "1.0.0",
      });
    });

    test("sections become nested objects", () => {
      const ini = `
name = root-value

[database]
host = localhost
port = 5432
`;
      expect(Bun.INI.parse(ini)).toEqual({
        name: "root-value",
        database: {
          host: "localhost",
          port: 5432,
        },
      });
    });

    test("dotted section names create deep nesting", () => {
      const ini = `
[foo.bar.baz]
key = value
`;
      expect(Bun.INI.parse(ini)).toEqual({
        foo: { bar: { baz: { key: "value" } } },
      });
    });

    test("boolean values", () => {
      expect(Bun.INI.parse("enabled = true\ndisabled = false")).toEqual({
        enabled: true,
        disabled: false,
      });
    });

    test("null value", () => {
      expect(Bun.INI.parse("x = null")).toEqual({ x: null });
    });

    test("numeric values are returned as strings (unquoted)", () => {
      // Unquoted values that look like numbers are returned as strings.
      // Use quoted values ("5432") if you need numeric types.
      expect(Bun.INI.parse("port = 5432\npi = 3.14")).toEqual({
        port: "5432",
        pi: "3.14",
      });
    });

    test("comment lines with ; are ignored", () => {
      const ini = `
; this is a comment
key = value
; another comment
`;
      expect(Bun.INI.parse(ini)).toEqual({ key: "value" });
    });

    test("comment lines with # are ignored", () => {
      const ini = `
# this is a comment
key = value
`;
      expect(Bun.INI.parse(ini)).toEqual({ key: "value" });
    });

    test("array values with [] notation", () => {
      const ini = `
colors[] = red
colors[] = green
colors[] = blue
`;
      expect(Bun.INI.parse(ini)).toEqual({
        colors: ["red", "green", "blue"],
      });
    });

    test("empty string input returns empty object", () => {
      expect(Bun.INI.parse("")).toEqual({});
    });

    test("throws on non-string input", () => {
      expect(() => Bun.INI.parse(null as any)).toThrow();
    });
  });

  describe("stringify", () => {
    test("basic key-value", () => {
      expect(Bun.INI.stringify({ name: "my-app", version: "1.0.0" })).toContain("name = my-app");
    });

    test("boolean values", () => {
      const out = Bun.INI.stringify({ enabled: true, disabled: false });
      expect(out).toContain("enabled = true");
      expect(out).toContain("disabled = false");
    });

    test("null value", () => {
      expect(Bun.INI.stringify({ x: null })).toContain("x = null");
    });

    test("numeric value", () => {
      expect(Bun.INI.stringify({ port: 5432 })).toContain("port = 5432");
    });

    test("sections for nested objects", () => {
      const out = Bun.INI.stringify({
        database: { host: "localhost", port: 5432 },
      });
      expect(out).toContain("[database]");
      expect(out).toContain("host = localhost");
      expect(out).toContain("port = 5432");
    });

    test("dotted section names for deep nesting", () => {
      const out = Bun.INI.stringify({
        foo: { bar: { key: "value" } },
      });
      expect(out).toContain("[foo.bar]");
      expect(out).toContain("key = value");
    });

    test("array values use [] notation", () => {
      const out = Bun.INI.stringify({ colors: ["red", "green", "blue"] });
      expect(out).toContain("colors[] = red");
      expect(out).toContain("colors[] = green");
      expect(out).toContain("colors[] = blue");
    });

    test("root scalars appear before sections", () => {
      const out = Bun.INI.stringify({
        name: "app",
        db: { host: "localhost" },
      });
      const nameIdx = out.indexOf("name = app");
      const sectionIdx = out.indexOf("[db]");
      expect(nameIdx).toBeGreaterThanOrEqual(0);
      expect(sectionIdx).toBeGreaterThanOrEqual(0);
      expect(nameIdx).toBeLessThan(sectionIdx);
    });

    test("round-trips string, boolean, and null values", () => {
      // Numbers are not round-tripped since unquoted numeric values parse as strings.
      // Strings, booleans, and null do round-trip correctly.
      const original = {
        name: "my-app",
        enabled: true,
        disabled: false,
        nothing: null,
        database: { host: "localhost", ssl: true },
      };
      const ini = Bun.INI.stringify(original);
      const parsed = Bun.INI.parse(ini);
      expect(parsed).toEqual(original);
    });

    test("empty object produces empty string", () => {
      expect(Bun.INI.stringify({})).toBe("");
    });

    test("throws on non-object input", () => {
      expect(() => Bun.INI.stringify("not an object" as any)).toThrow();
    });
  });
});

describe("parse ini", () => {
  test("weird section", () => {
    const ini = /* ini */ `
[foo\\]]
lol = true
`;

    expect(parse(ini)).toEqual({ "[foo\\]]": true, "lol": true });
  });

  test("really long input", () => {
    const ini = /* ini */ `
[${Array(1024).fill("a").join("")}.lol.this.be.long]
wow = 'hi'
`;

    expect(parse(ini)).toEqual({
      [`${Array(1024).fill("a").join("")}`]: {
        lol: {
          this: {
            be: {
              long: {
                wow: "hi",
              },
            },
          },
        },
      },
    });
  });
  describe("env vars", () => {
    // Tests translated from npm's workspaces/config/test/env-replace.js
    envVarTest({
      name: "replaces multiple defined variables",
      ini: "hi = ${FOO}${BAR}",
      env: { FOO: "bar", BAR: "baz" },
      expected: { hi: "barbaz" },
    });

    envVarTest({
      name: "replaces mixed defined/undefined variables with ? modifier",
      ini: "hi = ${FOO?}${BAZ?}",
      env: { FOO: "bar" },
      expected: { hi: "bar" },
    });

    envVarTest({
      name: "escapes normal variable",
      ini: "hi = \\${FOO}",
      env: { FOO: "bar" },
      expected: { hi: "${FOO}" },
    });

    envVarTest({
      name: "double escape allows replacement",
      ini: "hi = \\\\${FOO}",
      env: { FOO: "bar" },
      expected: { hi: "\\bar" },
    });

    envVarTest({
      name: "triple escape prevents replacement",
      ini: "hi = \\\\\\${FOO}",
      env: { FOO: "bar" },
      expected: { hi: "\\${FOO}" },
    });

    envVarTest({
      name: "leaves undefined variable unreplaced",
      ini: "hi = ${BAZ}",
      env: { FOO: "bar" },
      expected: { hi: "${BAZ}" },
    });

    envVarTest({
      name: "escapes undefined variable",
      ini: "hi = \\${BAZ}",
      env: { FOO: "bar" },
      expected: { hi: "${BAZ}" },
    });

    envVarTest({
      name: "double escape with undefined variable",
      ini: "hi = \\\\${BAZ}",
      env: { FOO: "bar" },
      expected: { hi: "\\${BAZ}" },
    });

    envVarTest({
      name: "escapes optional variable",
      ini: "hi = \\${FOO?}",
      env: { FOO: "bar" },
      expected: { hi: "${FOO?}" },
    });

    envVarTest({
      name: "double escape allows optional replacement",
      ini: "hi = \\\\${FOO?}",
      env: { FOO: "bar" },
      expected: { hi: "\\bar" },
    });

    envVarTest({
      name: "replaces undefined variable with empty string when using ? modifier",
      ini: "hi = ${BAZ?}",
      env: { FOO: "bar" },
      expected: { hi: "" },
    });

    envVarTest({
      name: "escapes undefined optional variable",
      ini: "hi = \\${BAZ?}",
      env: { FOO: "bar" },
      expected: { hi: "${BAZ?}" },
    });

    envVarTest({
      name: "double escape with undefined optional variable results in empty replacement",
      ini: "hi = \\\\${BAZ?}",
      env: { FOO: "bar" },
      expected: { hi: "\\" },
    });

    // Original bun tests
    envVarTest({
      name: "escaped",
      ini: "hi = \\${NODE_ENV}",
      env: { NODE_ENV: "production" },
      expected: { hi: "${NODE_ENV}" },
    });

    envVarTest({
      name: "escaped2",
      ini: "hi = \\\\${NODE_ENV}",
      env: { NODE_ENV: "production" },
      expected: { hi: "\\production" },
    });

    envVarTest({
      name: "backslashes",
      ini: "filepath=C:\\Home\\someuser\\My Documents\nfilepath2=\\\\\\\\TwoBackslashes",
      env: {},
      expected: { filepath: "C:\\Home\\someuser\\My Documents", filepath2: "\\\\TwoBackslashes" },
    });

    envVarTest({
      name: "basic",
      ini: /* ini */ `
hello = \${LOL}
      `,
      env: { LOL: "hi" },
      expected: { hello: "hi" },
    });

    envVarTest({
      name: "no val",
      ini: /* ini */ `
hello = \${oooooooooooooooogaboga}
      `,
      env: {},
      expected: { hello: "${oooooooooooooooogaboga}" },
    });

    envVarTest({
      name: "concat",
      ini: /* ini */ `
hello = greeting: \${LOL}
      `,
      env: { LOL: "hi" },
      expected: { hello: "greeting: hi" },
    });

    envVarTest({
      name: "nesting selects the inner most",
      ini: /* ini */ `
hello = greeting: \${what\${LOL}lol}
      `,
      env: { LOL: "hi" },
      expected: { hello: "greeting: ${whathilol}" },
    });

    envVarTest({
      name: "nesting 2 selects the inner most",
      ini: /* ini */ `
hello = greeting: \${what\${omg\${LOL}why}lol}
      `,
      env: { LOL: "hi" },
      expected: { hello: "greeting: ${what${omghiwhy}lol}" },
    });

    envVarTest({
      name: "unclosed",
      ini: /* ini */ `
hello = greeting: \${LOL
      `,
      env: { LOL: "hi" },
      expected: { hello: "greeting: ${LOL" },
    });

    envVarTest({
      name: "double quoted env var",
      ini: /* ini */ `
hello = "\${LOL}"
      `,
      env: { LOL: "hi" },
      expected: { hello: "hi" },
    });

    envVarTest({
      name: "single quoted env var",
      ini: /* ini */ `
hello = '\${LOL}'
      `,
      env: { LOL: "hi" },
      expected: { hello: "hi" },
    });

    envVarTest({
      name: "double quoted env var with prefix",
      ini: /* ini */ `
hello = "Bearer \${TOKEN}"
      `,
      env: { TOKEN: "secret123" },
      expected: { hello: "Bearer secret123" },
    });

    envVarTest({
      name: "double quoted env var not found leaves as-is",
      ini: /* ini */ `
hello = "\${NOTFOUND}"
      `,
      env: {},
      expected: { hello: "${NOTFOUND}" },
    });

    envVarTest({
      name: "unquoted optional env var expands to empty when not found",
      ini: /* ini */ `
hello = \${NOTFOUND?}
      `,
      env: {},
      expected: { hello: "" },
    });

    envVarTest({
      name: "unquoted optional env var expands to value when found",
      ini: /* ini */ `
hello = \${TOKEN?}
      `,
      env: { TOKEN: "secret" },
      expected: { hello: "secret" },
    });

    envVarTest({
      name: "double quoted optional env var expands to empty when not found",
      ini: /* ini */ `
hello = "\${NOTFOUND?}"
      `,
      env: {},
      expected: { hello: "" },
    });

    envVarTest({
      name: "double quoted optional env var expands to value when found",
      ini: /* ini */ `
hello = "\${TOKEN?}"
      `,
      env: { TOKEN: "secret" },
      expected: { hello: "secret" },
    });

    envVarTest({
      name: "single quoted optional env var expands to empty when not found",
      ini: /* ini */ `
hello = '\${NOTFOUND?}'
      `,
      env: {},
      expected: { hello: "" },
    });

    envVarTest({
      name: "unquoted optional env var with prefix",
      ini: /* ini */ `
hello = Bearer \${TOKEN?}
      `,
      env: {},
      expected: { hello: "Bearer " },
    });

    envVarTest({
      name: "double quoted optional env var with prefix",
      ini: /* ini */ `
hello = "Bearer \${TOKEN?}"
      `,
      env: {},
      expected: { hello: "Bearer " },
    });

    // Note: In JSON strings, \$ is just $ (backslash doesn't escape $)
    // So "\\${LOL}" in .npmrc becomes "\${LOL}" after JSON parsing, which expands to "\hi"
    // This matches npm behavior where escaping env vars in quoted strings requires \\$
    envVarTest({
      name: "double quoted with backslash before env var",
      ini: /* ini */ `
hello = "\\\\$\{LOL}"
      `,
      env: { LOL: "hi" },
      expected: { hello: "\\hi" },
    });

    function envVarTest(args: { name: string; ini: string; env: Record<string, string>; expected: any }) {
      const { name, ini, env, expected } = args;
      test(name, async () => {
        const tempdir = tempDirWithFiles("hi", { "foo.ini": ini });
        const inipath = `${tempdir}/foo.ini`.replaceAll("\\", "/");
        const code = /* ts */ `
const { iniInternals } = require("bun:internal-for-testing");
const { parse } = iniInternals;

const ini = await Bun.$\`cat ${inipath}\`.text()

console.log(JSON.stringify(parse(ini)))
        `;

        const result = await Bun.$`${bunExe()} -e ${code}`.env({ ...bunEnv, ...env }).json();
        expect(result).toEqual(expected);
      });
    }
  });

  it("works with unicode in the .ini file", () => {
    let ini /* ini */ = `
hi👋lol = 'lol hi 👋'
`;

    expect(parse(ini)).toEqual({
      "hi👋lol": "lol hi 👋",
    });

    ini = /* ini */ `
[😎.🫒.🤦‍♀️]
lol = 'wtf'
    `;

    expect(parse(ini)).toEqual({
      "😎": {
        "🫒": {
          "🤦‍♀️": {
            lol: "wtf",
          },
        },
      },
    });
  });

  it("matches stupid npm/ini behavior", () => {
    let ini /* ini */ = `
'{ "what": "is this" }' = seriously?
`;

    let result = parse(ini);
    expect(result).toEqual({
      "[Object object]": "seriously?",
    });

    ini = /* ini */ `
'[1, 2, 3]' = cmon man
`;

    result = parse(ini);
    expect(result).toEqual({
      "1,2,3": "cmon man",
    });
  });

  test("basic", () => {
    const ini = /* ini */ `
    hello = 'friends'
    `;

    expect(parse(ini)).toEqual({
      hello: "friends",
    });
  });

  test("basic sections", () => {
    const ini = /* ini */ `
hello = 'friends'

[foo]
bar = 'baz'
    `;

    expect(parse(ini)).toEqual({
      hello: "friends",
      foo: {
        bar: "baz",
      },
    });
  });

  test("key and then section edgecase", () => {
    const ini = /* ini */ `
foo = 'hihihi'

[foo]
isbar = 'lol'
    `;

    expect(parse(ini)).toEqual({
      foo: "hihihi",
    });
  });

  describe("duplicate properties", () => {
    test("decode with duplicate properties", () => {
      const ini = /* ini */ `
zr[] = deedee
zr=123
ar[] = one
ar[] = three
str = 3
brr = 1
brr = 2
brr = 3
brr = 3
`;

      expect(parse(ini)).toEqual({
        zr: ["deedee", "123"],
        ar: ["one", "three"],
        str: "3",
        brr: "3",
      });
    });
  });

  test("bigboi", async () => {
    const foo = await Bun.$`cat ${__dirname}/foo.ini`.text();
    const result = parse(foo);
    console.log(JSON.stringify(result));
    expect(result).toEqual({
      " xa  n          p ": '"\r\nyoyoyo\r\r\n',
      "[disturbing]": "hey you never know",
      "a": {
        "[]": "a square?",
        "av": "a val",
        "b": {
          "c": {
            "e": "1",
            "j": "2",
          },
        },
        "cr": ["four", "eight"],
        "e": '{ o: p, a: { av: a val, b: { c: { e: "this [value]" } } } }',
        "j": '"{ o: "p", a: { av: "a val", b: { c: { e: "this [value]" } } } }"',
      },
      "a with spaces": "b  c",
      "ar": ["one", "three", "this is included"],
      "b": {},
      "br": "warm",
      "eq": "eq=eq",
      "false": false,
      "null": null,
      "o": "p",
      "s": "something",
      "s1": "\"something'",
      "s2": "something else",
      "s3": "",
      "s4": "",
      "s5": "   ",
      "s6": " a ",
      "s7": true,
      "true": true,
      "undefined": "undefined",
      "x.y.z": {
        "a.b.c": {
          "a.b.c": "abc",
          "nocomment": "this; this is not a comment",
          "noHashComment": "this# this is not a comment",
        },
        "x.y.z": "xyz",
      },
      "zr": ["deedee"],
    });
  });

  describe("truncated/invalid utf-8", () => {
    test("bare continuation byte (0x80) should not crash", () => {
      // 0x80 is a continuation byte without a leading byte
      // utf8ByteSequenceLength returns 0, which must not hit unreachable
      const ini = Buffer.concat([Buffer.from("key = "), Buffer.from([0x80])]).toString("latin1");
      // Should not crash - just parse gracefully
      expect(() => parse(ini)).not.toThrow();
    });

    test("truncated 2-byte sequence at end of value", () => {
      // 0xC0 is a 2-byte lead byte, but there's no continuation byte following
      const ini = Buffer.concat([Buffer.from("key = "), Buffer.from([0xc0])]).toString("latin1");
      expect(() => parse(ini)).not.toThrow();
    });

    test("truncated 3-byte sequence at end of value", () => {
      // 0xE0 is a 3-byte lead byte, but only 0 continuation bytes follow
      const ini = Buffer.concat([Buffer.from("key = "), Buffer.from([0xe0])]).toString("latin1");
      expect(() => parse(ini)).not.toThrow();
    });

    test("truncated 3-byte sequence with 1 continuation byte at end", () => {
      // 0xE0 is a 3-byte lead byte, but only 1 continuation byte follows
      const ini = Buffer.concat([Buffer.from("key = "), Buffer.from([0xe0, 0x80])]).toString("latin1");
      expect(() => parse(ini)).not.toThrow();
    });

    test("truncated 4-byte sequence at end of value", () => {
      // 0xF0 is a 4-byte lead byte, but only 0 continuation bytes follow
      const ini = Buffer.concat([Buffer.from("key = "), Buffer.from([0xf0])]).toString("latin1");
      expect(() => parse(ini)).not.toThrow();
    });

    test("truncated 4-byte sequence with 1 continuation byte at end", () => {
      const ini = Buffer.concat([Buffer.from("key = "), Buffer.from([0xf0, 0x80])]).toString("latin1");
      expect(() => parse(ini)).not.toThrow();
    });

    test("truncated 4-byte sequence with 2 continuation bytes at end", () => {
      const ini = Buffer.concat([Buffer.from("key = "), Buffer.from([0xf0, 0x80, 0x80])]).toString("latin1");
      expect(() => parse(ini)).not.toThrow();
    });

    test("truncated 2-byte sequence in escaped context", () => {
      // Backslash followed by a 2-byte lead byte at end of value
      const ini = Buffer.concat([Buffer.from("key = \\"), Buffer.from([0xc0])]).toString("latin1");
      expect(() => parse(ini)).not.toThrow();
    });

    test("bare continuation byte in escaped context", () => {
      const ini = Buffer.concat([Buffer.from("key = \\"), Buffer.from([0x80])]).toString("latin1");
      expect(() => parse(ini)).not.toThrow();
    });
  });
});

